          <li>nombre des page:{books.page}</li>
        </ul>
      </div>
      <div className="flex">
        <Button className="bg-green-400" onClick={() => navigate(`/bookUpdate/${id}`)}>
          modifier
        </Button>
        <Button className="bg-red-300" onClick={handleClick} >supprimer</Button>
      </div>
    </div>
  );
};

export default BookShow;
